-- PASO 1: EJECUTA ESTA ÚNICA LÍNEA PRIMERO (Selecciónala y córrela sola)
ALTER TYPE public.silo_type ADD VALUE IF NOT EXISTS 'sinsilo';

-- -------- UNA VEZ EJECUTADA LA LÍNEA ANTERIOR, EJECUTA ESTOS DOS PASOS JUNTOS --------

-- Paso 2: Mover temporalmente TODOS los documentos del silo "personal" a "sinsilo" (Sin Silo)
UPDATE public.documents SET silo = 'sinsilo' WHERE silo = 'personal';

